function fetchData() {
  return new Promise((resolve, reject) => {
    setTimeout(() => {
      const data = { id: 1, message: 'Hello, World!' };
      resolve(data);
    }, 1000);
  });
}

fetchData()
  .then(response => {
    console.log('Data received:', response);
  })
  .catch(error => {
    console.error('Error:', error);
  });

async function getData() {
  try {
    const response = await fetchData();
    console.log('Data received:', response);
  } catch (error) {
    console.error('Error:', error);
  }
}

getData();

