import weakref

class Cache:
    def __init__(self):
        self._data = weakref.WeakValueDictionary()

    def add(self, key, obj):
        self._data[key] = obj

cache = Cache()

# Objects not referenced elsewhere will be garbage collected automatically

-- Create categories table to organize product types
CREATE TABLE categories (
    category_id INT PRIMARY KEY AUTO_INCREMENT,
    category_name VARCHAR(100) NOT NULL
);

-- Create products table with reference to categories
CREATE TABLE products (
    product_id INT PRIMARY KEY AUTO_INCREMENT,
    product_name VARCHAR(255) NOT NULL,
    category_id INT,
    price DECIMAL(10, 2) NOT NULL,
    FOREIGN KEY (category_id) REFERENCES categories(category_id)
);

-- Create inventory table to track stock for each product
CREATE TABLE inventory (
    product_id INT PRIMARY KEY,
    stock_quantity INT NOT NULL DEFAULT 0,
    FOREIGN KEY (product_id) REFERENCES products(product_id)
);
